import { describe, expect, it } from 'vitest';
import {
  THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
  THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
  THOTH_PROMPT_FEEDBACK_THEOREM,
  assertThothPromptFeedbackResponse,
  isThothPromptFeedbackResponse,
  validateThothPromptFeedbackResponse,
  type ThothPromptFeedbackAdmissionRejection,
  type ThothPromptFeedbackResponse,
} from '../src/thoth-prompt-feedback';

describe('Thoth prompt-feedback host contract', () => {
  it('accepts the native Rust prompt-feedback response shape with residue theorem', () => {
    const response = canonicalResponse();

    expect(isThothPromptFeedbackResponse(response)).toBe(true);
    const validation = validateThothPromptFeedbackResponse(response);
    expect(validation.ok).toBe(true);
    if (validation.ok) {
      const typed: ThothPromptFeedbackResponse = validation.value;
      expect(typed.rejection_residue_theorem).toBe(
        THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
      );
      expect(typed.admission_rejections[0]?.rejection_residue_theorem).toBe(
        THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
      );
    }
  });

  it('requires top-level rejection residue theorem at type and runtime boundaries', () => {
    const missingResidueResponse = {
      context: null,
      line_count: 0,
      theorem: THOTH_PROMPT_FEEDBACK_THEOREM,
      admissibility_theorem:
        THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
      accepted_frame_count: 0,
      rejected_frame_count: 1,
      input_frame_count: 1,
      admission_rejections: [canonicalAdmissionRejection()],
    } satisfies Omit<
      ThothPromptFeedbackResponse,
      'rejection_residue_theorem'
    >;

    // @ts-expect-error rejection_residue_theorem is required by the host contract.
    const typeRejectedResponse: ThothPromptFeedbackResponse =
      missingResidueResponse;

    expect(isThothPromptFeedbackResponse(typeRejectedResponse)).toBe(false);
    expect(validateThothPromptFeedbackResponse(typeRejectedResponse)).toEqual({
      ok: false,
      reason: `rejection_residue_theorem expected ${THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM} got undefined`,
    });
  });

  it('rejects a noncanonical top-level rejection residue theorem', () => {
    const response = {
      ...canonicalResponse(),
      rejection_residue_theorem: 'Gnosis.BadResidueTheorem',
    };

    expect(isThothPromptFeedbackResponse(response)).toBe(false);
    expect(() => assertThothPromptFeedbackResponse(response)).toThrow(
      /rejection_residue_theorem expected Gnosis\.ThothMindBodySpiritScribe\.prompt_feedback_admission_rejection_residue_preserved/,
    );
  });

  it('requires rejection residue theorem on each admission rejection', () => {
    const {
      rejection_residue_theorem: _dropped,
      ...missingResidueAdmissionRejection
    } = canonicalAdmissionRejection();
    const response = {
      ...canonicalResponse(),
      admission_rejections: [missingResidueAdmissionRejection],
    };

    expect(isThothPromptFeedbackResponse(response)).toBe(false);
    expect(validateThothPromptFeedbackResponse(response)).toEqual({
      ok: false,
      reason: `admission_rejections[0].rejection_residue_theorem expected ${THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM} got undefined`,
    });
  });

  it('rejects noncanonical admission-rejection theorem citations', () => {
    const response = {
      ...canonicalResponse(),
      admission_rejections: [
        {
          ...canonicalAdmissionRejection(),
          expected_theorem: 'Gnosis.BadAdmissibilityTheorem',
        },
      ],
    };

    expect(isThothPromptFeedbackResponse(response)).toBe(false);
    expect(validateThothPromptFeedbackResponse(response)).toEqual({
      ok: false,
      reason: `admission_rejections[0].expected_theorem expected ${THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM} got "Gnosis.BadAdmissibilityTheorem"`,
    });
  });
});

function canonicalAdmissionRejection(): ThothPromptFeedbackAdmissionRejection {
  return {
    frame_kind: 'thoth.conversation.consciousness.v1',
    source_id: 'pneuma-think-input',
    sequence: 2002,
    reason: 'missing_scribe_admissibility_theorem',
    observed_theorem: null,
    expected_theorem: THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
    rejection_residue_theorem:
      THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
  };
}

function canonicalResponse(): ThothPromptFeedbackResponse {
  return {
    context: null,
    line_count: 0,
    theorem: THOTH_PROMPT_FEEDBACK_THEOREM,
    admissibility_theorem: THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
    rejection_residue_theorem:
      THOTH_MIND_BODY_SPIRIT_PROMPT_FEEDBACK_REJECTION_RESIDUE_THEOREM,
    accepted_frame_count: 0,
    rejected_frame_count: 1,
    input_frame_count: 1,
    admission_rejections: [canonicalAdmissionRejection()],
  };
}
